using HaCreator.MapEditor; using HaCreator.MapEditor.Instance; using HaCreator.MapEditor.UndoRedo; using System.Collections.Generic; using System.Windows;
namespace HaCreator.GUI.InstanceEditor { public partial class MassZmEditor:Window { public IContainsLayerInfo[] items; private readonly Board board; public MassZmEditor(IContainsLayerInfo[] items,Board board,int zm){InitializeComponent();this.items=items;this.board=board;InstanceEditorDialogSupport.SetInt(zmInput,zm);} private void CancelButton_Click(object s,RoutedEventArgs e)=>Close(); private void OkButton_Click(object s,RoutedEventArgs e){lock(board.ParentControl){int value=InstanceEditorDialogSupport.GetInt(zmInput);List<UndoRedoAction> actions=new();foreach(IContainsLayerInfo item in items){actions.Add(UndoRedoManager.zMChanged(item,item.PlatformNumber,value));item.PlatformNumber=value;}if(actions.Count>0)board.UndoRedoMan.AddUndoBatch(actions);}Close();}}}
